const results = $.steps.retrieveKnowledge.response.results || [];
const question = $.input.question;

let contextChunks = '';
const sources = [];

results.forEach((r, i) => {
  const text = (r.text || '').slice(0, 1200);
  contextChunks += '--- CHUNK ' + (i + 1) + ' ---\n';
  contextChunks += 'Title: ' + (r.title || 'Untitled') + '\n';
  contextChunks += 'URL: ' + r.url + '\n';
  if (r.publishedDate) contextChunks += 'Published: ' + r.publishedDate + '\n';
  contextChunks += 'Content:\n' + text + '\n\n';

  sources.push({ index: i + 1, title: r.title || 'Untitled', url: r.url, snippet: text.slice(0, 200) });
});

return { contextChunks, sources, sourceCount: results.length };

const question = $.input.question;
const context = $.steps.compileChunks.output;

let prompt = 'You are a knowledgeable AI assistant using Retrieval Augmented Generation. Answer the user question based PRIMARILY on the retrieved knowledge chunks below. Ground your answer in the source material.\n\n';
prompt += 'USER QUESTION: ' + question + '\n\n';
prompt += 'RETRIEVED KNOWLEDGE:\n' + context.contextChunks + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Synthesize information from multiple sources into a coherent answer\n';
prompt += '- Cite source numbers [1], [2], etc. when referencing information\n';
prompt += '- If sources conflict, note the discrepancy and present both views\n';
prompt += '- If retrieved knowledge is insufficient, say so and provide what you can\n';
prompt += '- Be thorough but concise\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "your synthesized answer with [N] source citations",\n';
prompt += '  "sourcesUsed": [1, 2, 3],\n';
prompt += '  "confidence": "high/medium/low",\n';
prompt += '  "keyPoints": ["main point 1", "main point 2"],\n';
prompt += '  "followUpQuestions": ["suggested follow-up question 1"],\n';
prompt += '  "summary": "one-sentence summary"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, sourcesUsed: [], confidence: 'low', keyPoints: [], summary: 'See raw answer' }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const sources = $.steps.compileChunks.output.sources || [];
const sourceCount = $.steps.compileChunks.output.sourceCount;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'RAG Knowledge Assistant', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answerText } });

if (ai.keyPoints && ai.keyPoints.length > 0) {
  blocks.push({ type: 'divider' });
  let kpText = '*Key Points:*\n';
  ai.keyPoints.forEach((kp, i) => { kpText += '  ' + (i + 1) + '. ' + kp + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kpText.slice(0, 1800) } });
}

const usedIndices = ai.sourcesUsed || [];
const usedSources = usedIndices.map(idx => sources.find(s => s.index === idx)).filter(Boolean);
if (usedSources.length > 0) {
  blocks.push({ type: 'divider' });
  let srcText = '*Sources:*\n';
  usedSources.slice(0, 5).forEach(s => {
    srcText += '[' + s.index + '] <' + s.url + '|' + s.title + '>\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText } });
}

if (ai.followUpQuestions && ai.followUpQuestions.length > 0) {
  let fuText = '*Follow-up questions:*\n';
  ai.followUpQuestions.slice(0, 3).forEach(q => { fuText += '  - ' + q + '\n'; });
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: fuText }] });
}

blocks.push({ type: 'divider' });
const confEmoji = ai.confidence === 'high' ? 'large_green_circle' : ai.confidence === 'medium' ? 'large_yellow_circle' : 'red_circle';
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':' + confEmoji + ': Confidence: ' + (ai.confidence || 'unknown') + ' | ' + sourceCount + ' sources retrieved' }] });

const fallbackText = 'RAG Answer: ' + (ai.summary || question);
return { blocks, fallbackText };
